mapper.select:
SELECT
    id, sender_uid, receiver_uid, sender_role, receiver_role, context_type, context_id, content, client_request_id,
    status, chat_access_status, room_id, decided_at, receiver_read, receiver_read_time, create_time, update_time
FROM tutor_application
WHERE sender_uid = #{senderUid}

      AND id < #{cursor}

ORDER BY id DESC
LIMIT #{pageSize}

SELECT
    id, sender_uid, receiver_uid, sender_role, receiver_role, context_type, context_id, content, client_request_id,
    status, chat_access_status, room_id, decided_at, receiver_read, receiver_read_time, create_time, update_time
FROM tutor_application
WHERE receiver_uid = #{receiverUid}

      AND id < #{cursor}

ORDER BY id DESC
LIMIT #{pageSize}

SELECT
    id, sender_uid, receiver_uid, sender_role, receiver_role, context_type, context_id, content, client_request_id,
    status, chat_access_status, room_id, decided_at, receiver_read, receiver_read_time, create_time, update_time
FROM tutor_application
WHERE sender_uid = #{senderUid}
  AND receiver_uid = #{receiverUid}
  AND context_type = #{contextType}
  AND context_id = #{contextId}
ORDER BY id DESC
LIMIT 1

SELECT COUNT(1)
FROM tutor_application
WHERE sender_uid = #{senderUid}
  AND create_time >= #{startTime}
  AND create_time < #{endTime}
